module RefModule(
    input wire clk,
    input wire reset,
    input wire signal,
    output reg crossing
);
reg previous_signal;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset) begin
        previous_signal <= 0;
        crossing <= 0;
    end else begin
        crossing <= (previous_signal && !signal) || (!previous_signal && signal);
        previous_signal <= signal;
    end
end
endmodule
